=== devices/ruckus.tcl ===
# Load RUCKUS environment and library
source $::env(RUCKUS_PROC_TCL)

# Load ruckus files
loadRuckusTcl "$::DIR_PATH/Marvell"
loadRuckusTcl "$::DIR_PATH/Maxim"
loadRuckusTcl "$::DIR_PATH/Microchip"

# Check for non-zero Vivado version (in-case non-Vivado project)
if {  $::env(VIVADO_VERSION) > 0.0} {
   loadRuckusTcl "$::DIR_PATH/Amphenol"
   loadRuckusTcl "$::DIR_PATH/AnalogDevices"
   loadRuckusTcl "$::DIR_PATH/Linear"
   loadRuckusTcl "$::DIR_PATH/Micron"
   loadRuckusTcl "$::DIR_PATH/Nxp"
   loadRuckusTcl "$::DIR_PATH/Silabs"
   loadRuckusTcl "$::DIR_PATH/Ti"
   loadRuckusTcl "$::DIR_PATH/transceivers"
   loadRuckusTcl "$::DIR_PATH/Xilinx"
}

=== devices/transceivers/ruckus.tcl ===
# Load RUCKUS environment and library
source $::env(RUCKUS_PROC_TCL)

# Load Source Code
loadSource -lib surf -dir "$::DIR_PATH/rtl"

=== xilinx/ruckus.tcl ===
# Load RUCKUS library
source $::env(RUCKUS_PROC_TCL)

# Check for non-zero Vivado version (in-case non-Vivado project)
if {  $::env(VIVADO_VERSION) > 0.0} {
   # Load the Core
   loadRuckusTcl "$::DIR_PATH/general"
   loadRuckusTcl "$::DIR_PATH/xvc-udp"
} else {
   loadSource -lib surf -path "$::DIR_PATH/general/rtl/SelectIoRxGearboxAligner.vhd"
   loadSource -lib surf -dir  "$::DIR_PATH/dummy"
}

# Get the family type
set family [getFpgaArch]

if { ${family} eq {artix7}  ||
     ${family} eq {kintex7} ||
     ${family} eq {virtex7} ||
     ${family} eq {zynq} } {
   loadRuckusTcl "$::DIR_PATH/7Series"
}

if { ${family} eq {kintexu} ||
     ${family} eq {virtexu} } {
   loadRuckusTcl "$::DIR_PATH/UltraScale"
}

if { ${family} eq {kintexuplus} ||
     ${family} eq {virtexuplus} ||
     ${family} eq {virtexuplusHBM} ||
     ${family} eq {zynquplus} ||
     ${family} eq {zynquplusRFSOC} } {
   loadRuckusTcl "$::DIR_PATH/UltraScale+"
}

if { ${family} eq {versal} } {
   loadRuckusTcl "$::DIR_PATH/Versal"
}

=== xilinx/7Series/ruckus.tcl ===
# Load RUCKUS library
source $::env(RUCKUS_PROC_TCL)

# Load the Core
loadRuckusTcl "$::DIR_PATH/general"
loadRuckusTcl "$::DIR_PATH/xadc"
loadRuckusTcl "$::DIR_PATH/sem"
loadSource -lib surf -dir  "$::DIR_PATH/dummy"

# Get the family type
set family [getFpgaArch]

if { ${family} == "artix7" } {
   loadRuckusTcl "$::DIR_PATH/gtp7"
}

if { ${family} == "kintex7" } {
   loadRuckusTcl "$::DIR_PATH/gtx7"
}

if { ${family} == "virtex7" } {
   loadRuckusTcl "$::DIR_PATH/gth7"
}

if { ${family} == "zynq" } {
   if { [ regexp "XC7Z(015|012).*" [string toupper "$::env(PRJ_PART)"] ] } {
      loadRuckusTcl "$::DIR_PATH/gtp7"
   } else {
      loadRuckusTcl "$::DIR_PATH/gtx7"
   }
}

